css = '.hero-btn-icon { width:22px; height:22px; display:inline-block; vertical-align:middle; margin-right:6px; color:currentColor; }\n.about-icon .hero-btn-icon { width:32px; height:32px; color:var(--accent,#2d8a4e); }\n'

with open("atlas/templates/atlas/index.html", encoding="utf-8") as f:
    content = f.read()

count = 0
for old, new in replacements:
    if old in content:
        content = content.replace(old, new, 1)
        count += 1
        print("OK:", old[:40])
    else:
        print("NO ENCONTRADO:", old[:40])

# Añadir CSS si no está
if "hero-btn-icon" not in content:
    content = content.replace("@keyframes fadeUp", css + "@keyframes fadeUp", 1)
    print("OK: CSS añadido")

with open("atlas/templates/atlas/index.html", "w", encoding="utf-8") as f:
    f.write(content)
print(f"DONE: {count} reemplazos")
